theme.custom_css_code:
.mystake-diagram {
  display: grid;
  gap: 14px;
  font-family: Arial, sans-serif;
  background: transparent;
}

.mystake-diagram-row {
  display: grid;
  grid-template-columns: 170px 1fr;
  gap: 14px;
  align-items: center;
}

.mystake-diagram-label {
  color: #d6d9e3;
  font-size: 14px;
  line-height: 1.35;
}

.mystake-diagram-track {
  position: relative;
  height: 40px;
  border-radius: 999px;
  background: rgba(255,255,255,0.06);
  overflow: hidden;
  border: 1px solid rgba(255,255,255,0.08);
}

.mystake-diagram-bar {
  height: 100%;
  border-radius: 999px;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  padding-right: 12px;
  box-sizing: border-box;
  color: #ffffff;
  font-size: 13px;
  font-weight: 700;
  background: linear-gradient(90deg, #6f58ff 0%, #8f7bff 100%);
  box-shadow: inset 0 0 0 1px rgba(255,255,255,0.08);
}

.mystake-diagram-bar span {
  white-space: nowrap;
}

@media (max-width: 767px) {
  .mystake-diagram-row {
    grid-template-columns: 1fr;
    gap: 8px;
  }

  .mystake-diagram-label {
    font-size: 13px;
  }

  .mystake-diagram-track {
    height: 36px;
  }
}
.mystake-games-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
  background: transparent;
}

.mystake-game-card {
  position: relative;
  padding: 20px 18px;
  border-radius: 18px;
  background:
    linear-gradient(180deg, rgba(255,255,255,0.06) 0%, rgba(255,255,255,0.025) 100%);
  border: 1px solid rgba(255,255,255,0.08);
  color: #ffffff;
  font-family: Arial, sans-serif;
  box-sizing: border-box;
  min-height: 150px;
  overflow: hidden;
}

.mystake-game-card::after {
  content: "";
  position: absolute;
  inset: auto -20% -35% auto;
  width: 120px;
  height: 120px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(113, 88, 255, 0.22) 0%, rgba(113, 88, 255, 0) 70%);
  pointer-events: none;
}

.mystake-game-icon {
  font-size: 28px;
  line-height: 1;
  margin-bottom: 14px;
}

.mystake-game-name {
  font-size: 18px;
  font-weight: 700;
  line-height: 1.2;
  margin-bottom: 8px;
}

.mystake-game-meta {
  font-size: 13px;
  line-height: 1.5;
  color: #b9c0d1;
  max-width: 220px;
}

@media (max-width: 991px) {
  .mystake-games-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 640px) {
  .mystake-games-grid {
    grid-template-columns: 1fr;
    gap: 12px;
  }

  .mystake-game-card {
    min-height: auto;
    padding: 18px 16px;
  }

  .mystake-game-name {
    font-size: 17px;
  }
}
.mystake-brand-table-wrap {
  width: 100%;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  background: transparent;
}

.mystake-brand-table {
  width: 100%;
  min-width: 640px;
  border-collapse: collapse;
  font-family: Arial, sans-serif;
  color: #f4f4f6;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  overflow: hidden;
}

.mystake-brand-table td {
  padding: 14px 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
  vertical-align: top;
  font-size: 14px;
  line-height: 1.45;
}

.mystake-brand-table tr:last-child td {
  border-bottom: none;
}

.mystake-brand-table td:first-child {
  width: 34%;
  color: #a8b0c2;
  font-weight: 600;
  white-space: nowrap;
}

.mystake-brand-table td:last-child {
  color: #ffffff;
}

@media (max-width: 767px) {
  .mystake-brand-table td {
    padding: 12px 14px;
    font-size: 13px;
  }
}
